const json = $input.item.json;
const f = json.fields || json.Felder || {};
const thema   = f.field_1  || f.Field_1  || "(kein Thema)";
const caption = String(f.field_10 || f.Field_10 || "").trim().replace(/^=+/, "");
const bildUrl = String(f.field_8  || f.Field_8  || "").trim();
const itemId  = parseInt(String(json.AUSWEIS || json.id || 0).trim(), 10);
const hatBild = bildUrl && bildUrl !== "0" && !/^0+$/.test(bildUrl) && bildUrl.startsWith("http");
const ersterAbsatz = caption.split(/\n\n/)[0].replace(/^=+/, "").trim();
return {
  json: {
    ...json,
    thema:              thema,
    caption:            caption,
    hook:               ersterAbsatz,
    bild_url:           hatBild ? bildUrl : "",
    hat_bild:           hatBild,
    sharepoint_item_id: itemId,
  }
};

const json = $input.item.json;
return {
  json: {
    final_bild_url:      json.bild_url,
    thema:               json.thema,
    sharepoint_item_id:  json.sharepoint_item_id,
    bild_quelle:         'manuell',
    generated_at:        new Date().toISOString()
  }
};

const json = $input.item.json;
const thema = json.thema || "Physiotherapie";
const hook  = json.hook  || "Gesundheit beginnt mit Bewegung.";
const LOGO_B64  = "";
const ZWEIG_B64 = "";
const gruen       = "#5a7a4a";
const creme       = "#f0ede4";
const braunDunkel = "#5d4739";
const braunMittel = "#7a5c46";
const braunLogo   = "#3d2810";
const weiss       = "#ffffff";
const schrift     = "'EB Garamond', Georgia, serif";
const themFontSize = thema.length > 20 ? "88px" : thema.length > 14 ? "104px" : "120px";
const hookFontSize = hook.length > 200 ? "28px" : hook.length > 120 ? "32px" : hook.length > 70 ? "36px" : "40px";
const html = `
<div style="width:1080px;height:1920px;position:relative;overflow:hidden;font-family:${schrift};">

  <!-- OBEN: Grün mit THEMA -->
  <div style="position:absolute;top:0;left:0;right:0;height:880px;background:${gruen};overflow:hidden;">

    <!-- Ginkgo-Zweig PNG (weiß → multiply → wird transparent auf grün) -->
    <img src="data:image/png;base64,${ZWEIG_B64}"
         style="position:absolute;top:-40px;right:-80px;width:620px;height:auto;
                mix-blend-mode:multiply;opacity:0.35;transform:rotate(-15deg);" />

    <!-- Logo oben links -->
    <div style="position:absolute;top:60px;left:60px;">
      <img src="data:image/png;base64,${LOGO_B64}"
           style="width:160px;height:160px;mix-blend-mode:lighten;" />
    </div>

    <!-- Ort -->
    <div style="position:absolute;top:88px;right:80px;">
      <div style="font-size:28px;letter-spacing:6px;color:rgba(255,255,255,0.55);font-family:${schrift};">LINTORF</div>
    </div>

    <!-- THEMA Text -->
    <div style="position:absolute;bottom:70px;left:80px;right:80px;">
      <div style="color:${weiss};font-size:${themFontSize};font-style:italic;font-family:${schrift};line-height:1.15;">${thema}</div>
    </div>
  </div>

  <!-- UNTEN: Creme mit Absatz + Branding -->
  <div style="position:absolute;bottom:0;left:0;right:0;height:1040px;background:${creme};">
    <div style="padding:70px 80px 0;font-size:${hookFontSize};color:${braunDunkel};font-style:italic;font-family:${schrift};line-height:1.65;">${hook}</div>
    <div style="margin:50px 80px;width:80px;height:3px;background:${gruen};"></div>
    <div style="position:absolute;bottom:80px;left:80px;right:80px;display:flex;align-items:center;gap:40px;">
      <div style="width:120px;height:120px;border-radius:50%;background:${braunLogo};overflow:hidden;flex-shrink:0;">
        <img src="data:image/png;base64,${LOGO_B64}" style="width:120px;height:120px;" />
      </div>
      <div>
        <div style="font-size:46px;font-weight:bold;font-family:${schrift};color:${braunDunkel};">Physio Fuchs</div>
        <div style="font-size:22px;letter-spacing:4px;color:${braunMittel};margin-top:8px;">THERAPIE · TRAINING · WELLNESS</div>
      </div>
    </div>
  </div>

</div>
`;
return {
  json: {
    html:            html,
    viewport_width:  1080,
    viewport_height: 1920,
    google_fonts:    "EB+Garamond",
    _meta: { thema: thema, sharepoint_item_id: json.sharepoint_item_id }
  }
};

const response = $input.item.json;
const prev = $('HTML Template generieren').item.json._meta;

const imageUrl = response.url || response.image_url || '';
if (!imageUrl) {
  throw new Error('Kein Bild-URL von hcti.io. Response: ' + JSON.stringify(response).substring(0, 300));
}

return {
  json: {
    final_bild_url:     imageUrl,
    thema:              prev?.thema || '',
    sharepoint_item_id: prev?.sharepoint_item_id || 0,
    bild_quelle:        'html',
    generated_at:       new Date().toISOString()
  }
};
